describe('Group C — Total score composition', () => {
  const maxUser: ScoringUser = {
    id: 'user-1',
    interests: ['basketball', 'running'],
    locationLat: 34.0522,
    locationLng: -118.2437,
    rating: 5,
    activityCount: 20,
  };

